f=pairdiffs(arr:@i64):@i64{
  let n=arr.len;
  let result=mut.@();
  lp(let i=0;i<n-1 as u64;i=i+1){
    let p=arr.get(i);
    let q=arr.get((i+1) as u64);
    result=result+@(q-p);
  };
  <result
};

